#include <bits/stdc++.h>
#define int long long
using namespace std;
int t, x;
int phi[10000005];
int qpow (int a, int b, int p) {
	int res = 1;
	while (b) {
		if (b & 1) {
			res = res * a % p;
		}
		a = a * a % p;
		b >>= 1;
	}
	return res;
}
void getphi () {
	phi[1] = 1; 
	for(int i = 2; i <= 1e7; i++) {
		if (!phi[i]) {
			for (int j = i; j <= 1e7; j += i) {
				if (!phi[j]) {
					phi[j] = j;
				}
				phi[j] = phi[j] / i * (i - 1);
			}
		}
	}
}
int dfs (int p) {
	if (p == 1) {
		return 0;
	}
	return qpow (2, dfs (phi[p]) + phi[p], p);
}
signed main() {
	getphi ();
	cin >> t;
	while (t--) {
		cin >> x;
		cout << dfs (x) << '\n';
	}
	return 0;
}
